mapper.select:
select

from 

where 1=1


	and
	(
	SECKILL_NAME LIKE CONCAT(CONCAT('%', #{pd.keywords}),'%')
	or
	SECKILL_MEMO LIKE CONCAT(CONCAT('%', #{pd.keywords}),'%')
	)



	and START_TIME >= #{pd.lastStart}



	and START_TIME <= #{pd.lastEnd}



	and SECKILL_STATE = #{pd.SECKILL_STATE}

order by str_to_date(START_TIME, '%H:%i:%S')
